using S = array<int, 6>;
S right(const S& a) {
	return { a[3], a[1], a[0], a[5], a[4], a[2] };
}
S left(const S& a) {
	return { a[2], a[1], a[5], a[0], a[4], a[3] };
}
S up(const S& a) {
	return { a[1], a[5], a[2], a[3], a[0], a[4] };
}
S down(const S& a) {
	return { a[4], a[0], a[2], a[3], a[5], a[1] };
}
S rotate(int x, const S& a) {
	if (x == 0)return down(a);
	else if (x == 1)return up(a);
	else if (x == 2)return right(a);
	else return left(a);
}
var snum = map<S, int>();
var nums = map<int, S>();
void init() {
	var init = S();
	fa(i, 0, 5)init[i] = i;
	int now = 0;
	if (!snum.count(init)) {
		snum[init] = now;
		nums[now] = init;
		now++;
	}
	while (now != 24) {
		int r = MT::randint<int>(0, 3);
		if (r == 0)init = right(init);
		else if (r == 1)init = left(init);
		else if (r == 2)init = up(init);
		else init = down(init);
		if (!snum.count(init)) {
			snum[init] = now;
			nums[now] = init;
			now++;
		}
	}
}
struct node {
	int x, y, st, d;
	S s;
};
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var c = vector<int>(6);
	fa(i, 0, 5)cin >> c[i];
	var dis = Vec3<int>(n + 1, m + 1, 24, INF);
	int sx, sy, tx, ty, ts; cin >> sx >> sy >> tx >> ty >> ts;

	var Q = queue<node>();
	var s = S();
	fa(i, 0, 5)s[i] = i;
	Q.push({ sx,sy,0,dis[sx][sy][0] = 0,s });
	while (Q.size()) {
		var[x, y, st, d, s] = Q.front();
		Q.pop();
		if (d > dis[x][y][st])continue;
		fa(k, 0, 3) {
			int nx = x + dx[k], ny = y + dy[k];
			if (nx < 1 or nx > n or ny < 1 or ny > m)continue;
			var ns = rotate(k, s);
			int nst = snum[ns];
			if (dis[nx][ny][nst] > dis[x][y][st] + 1) {
				dis[nx][ny][nst] = dis[x][y][st] + 1;
				Q.push({ nx,ny,nst,dis[nx][ny][nst],ns });
			}
		}
	}

	for (var& [s, _] : snum) {
		if (c[s[5]] != ts)continue;
		int st = snum[s];
		if (dis[tx][ty][st] >= INF)continue;
		cout << dis[tx][ty][st] << endl;
		return;
	}
	cout << -1 << endl;
	return;
}
